#include <bits/stdc++.h>
using namespace std;

const int N=3010;

int n,nxt[N][26],lst[26],ans;
char s[N],t[N];
unordered_map<unsigned long long,bool> mp;

int main(){
    scanf("%d",&n);
    scanf("%s%s",s+1,t+1);
    for(int i=0;i<26;i++) lst[i]=n+1;
    for(int i=n;i>=0;i--){
        for(int j=0;j<26;j++)
            nxt[i][j]=lst[j];
        if(i)
            lst[s[i]-'a']=i;
    }
    for(int i=1;i<=n;i++){
        unsigned long long h=0;
        int p=0;
        for(int j=i;j<=n;j++){
            p=nxt[p][t[j]-'a'];
            if(p>n) break;
            h=31*h+t[j]-'a'+1;
            if(!mp.count(h)){
                ans++;
                mp[h]=1;
            }
        }
    }
    printf("%d",ans);
    return 0;
}
